sql:
SELECT e.name AS employee_name, d.name AS department_name
FROM employees e
LEFT JOIN departments d ON e.department_id = d.id;

SELECT e.name AS employee_name, d.name AS department_name
FROM employees e
INNER JOIN departments d ON e.department_id = d.id;

SELECT d.name AS department_name, e.name AS employee_name
FROM departments d
LEFT JOIN employees e ON d.id = e.department_id;

SELECT e.name AS employee_name, d.name AS department_name
FROM employees e
FULL OUTER JOIN departments d ON e.department_id = d.id;

SELECT e.name AS employee_name, p.title AS project_title
FROM employees e
CROSS JOIN projects p;

SELECT e.name AS employee_name, m.name AS manager_name
FROM employees e
LEFT JOIN employees m ON e.manager_id = m.id;

SELECT e1.name AS emp1, e2.name AS emp2, e1.salary
FROM employees e1
INNER JOIN employees e2 ON e1.salary = e2.salary AND e1.id < e2.id;

SELECT c.name AS customer_name, o.order_date
FROM customers c
LEFT JOIN orders o ON c.id = o.customer_id;

SELECT c.name AS customer_name, o.id AS order_id
FROM customers c
INNER JOIN orders o ON c.id = o.customer_id;

SELECT o.id AS order_id, c.email AS customer_email
FROM orders o
LEFT JOIN customers c ON o.customer_id = c.id;

SELECT a.name AS author_name, b.title AS book_title
FROM authors a
LEFT JOIN books b ON a.id = b.author_id;

SELECT b.title AS book_title, p.name AS publisher_name
FROM books b
LEFT JOIN publishers p ON b.publisher_id = p.id;

SELECT p.name AS publisher_name, b.title AS book_title
FROM publishers p
LEFT JOIN books b ON p.id = b.publisher_id;

SELECT a.name AS author_name, p.name AS publisher_name, a.city
FROM authors a
INNER JOIN publishers p ON a.city = p.city;

SELECT f.flight_number, a.code AS airport_code
FROM flights f
LEFT JOIN airports a ON f.arrival_airport_id = a.id;

SELECT a.name AS airport_name, f.flight_number
FROM airports a
LEFT JOIN flights f ON a.id = f.arrival_airport_id;

SELECT p.name AS product_name, c.name AS category_name
FROM products p
LEFT JOIN categories c ON p.category_id = c.id;

SELECT c.name AS category_name, p.name AS product_name
FROM categories c
INNER JOIN products p ON c.id = p.category_id;

SELECT c.name AS category_name, p.name AS product_name
FROM categories c
LEFT JOIN products p ON c.id = p.category_id;

SELECT p.name AS product_name, c.name AS category_name
FROM products p
FULL OUTER JOIN categories c ON p.category_id = c.id;

SELECT p.name AS product_name, s.city AS store_location
FROM products p
CROSS JOIN stores s;

SELECT p1.name AS prod1, p2.name AS prod2, p1.price
FROM products p1
INNER JOIN products p2 ON p1.category_id = p2.category_id AND p1.price = p2.price AND p1.id < p2.id;

SELECT u.username, d.filename
FROM users u
LEFT JOIN documents d ON u.id = d.user_id;

SELECT u.username, d.filename
FROM users u
INNER JOIN documents d ON u.id = d.user_id;

SELECT d.filename, u.username
FROM documents d
LEFT JOIN users u ON d.user_id = u.id;

SELECT s.name AS supplier_name, p.part_name
FROM suppliers s
LEFT JOIN parts p ON s.id = p.supplier_id;

SELECT p.part_name, s.name AS supplier_name
FROM parts p
INNER JOIN suppliers s ON p.supplier_id = s.id;

SELECT d.name AS department_name, o.office_number
FROM departments d
RIGHT JOIN offices o ON d.office_id = o.id;

SELECT s.name AS student, a.name AS advisor
FROM students s
INNER JOIN advisors a ON s.first_name = a.first_name;

SELECT p.title, c.comment_text
FROM posts p
LEFT JOIN comments c ON p.id = c.post_id;

SELECT p.title, c.comment_text
FROM posts p
INNER JOIN comments c ON p.id = c.post_id;

SELECT c.comment_text, p.title
FROM comments c
LEFT JOIN posts p ON c.post_id = p.id;

SELECT a.name, art.title
FROM authors a
FULL OUTER JOIN articles art ON a.article_id = art.id;

SELECT t.title AS task_title, pre.title AS prerequisite_title
FROM tasks t
LEFT JOIN tasks pre ON t.prereq_id = pre.id;

SELECT e.name AS employee_name, m.name AS manager_name
FROM employees e
INNER JOIN employees m ON e.manager_id = m.id;

SELECT m1.name AS member1, m2.name AS member2
FROM members m1
INNER JOIN members m2 ON m1.id < m2.id;

SELECT b.title, t.language, t.translated_title
FROM books b
LEFT JOIN translations t ON b.id = t.book_id;

SELECT b.title, t.language, t.translated_title
FROM books b
INNER JOIN translations t ON b.id = t.book_id;

SELECT a.account_number, b.name AS branch_name
FROM accounts a
RIGHT JOIN branches b ON a.branch_id = b.id;

SELECT s.name AS student_name, a.name AS advisor_name
FROM students s
FULL OUTER JOIN advisors a ON s.advisor_id = a.id;

SELECT p1.name AS prod1, p2.name AS prod2, p1.weight
FROM products p1
INNER JOIN products p2 ON p1.weight = p2.weight AND p1.id < p2.id;

SELECT c.name, co.code
FROM customers c
LEFT JOIN coupons co ON c.coupon_id = co.id;

SELECT c.name, co.code
FROM customers c
INNER JOIN coupons co ON c.coupon_id = co.id;

SELECT co.code, c.name
FROM coupons co
LEFT JOIN customers c ON co.id = c.coupon_id;

SELECT i.name AS item_name, oi.order_id
FROM items i
LEFT JOIN order_items oi ON i.id = oi.item_id;

SELECT e.title, v.name AS venue_name
FROM events e
LEFT JOIN venues v ON e.venue_id = v.id;

SELECT v.name AS venue_name, e.title
FROM venues v
LEFT JOIN events e ON v.id = e.venue_id;

SELECT e.title, v.name AS venue_name
FROM events e
FULL OUTER JOIN venues v ON e.venue_id = v.id;

SELECT e.title, v.name AS venue_name
FROM events e
INNER JOIN venues v ON e.venue_id = v.id;

SELECT u1.name AS user1, u2.name AS user2, u1.state
FROM users u1
INNER JOIN users u2 ON u1.state = u2.state AND u1.id < u2.id;

SELECT e.name, o.office_name
FROM employees e
RIGHT JOIN offices o ON e.office_id = o.id;

SELECT a.asset_name, u.name
FROM assets a
FULL OUTER JOIN users u ON a.user_id = u.id;

SELECT t.task_name, e.name
FROM tasks t
LEFT JOIN employees e ON t.assigned_to = e.id;

SELECT t.task_name, e.name
FROM tasks t
INNER JOIN employees e ON t.assigned_to = e.id;

SELECT e.name, t.task_name
FROM employees e
LEFT JOIN tasks t ON e.id = t.assigned_to;

SELECT m.title, r.rating, r.comment
FROM movies m
LEFT JOIN reviews r ON m.id = r.movie_id;

SELECT m.title, r.rating, r.comment
FROM movies m
INNER JOIN reviews r ON m.id = r.movie_id;

SELECT r.comment, m.title
