SELECT m1.title AS movie1, m2.title AS movie2, m1.release_year
FROM movies m1
INNER JOIN movies m2 ON m1.release_year = m2.release_year AND m1.id < m2.id;

SELECT c.name, cc.card_number
FROM customers c
