SELECT u1.name AS user1, u2.name AS user2, u1.email
FROM users u1
INNER JOIN users u2 ON u1.email = u2.email AND u1.id < u2.id;

SELECT d.division_name, s.store_name
FROM divisions d
LEFT JOIN stores s ON d.id = s.division_id;

SELECT s.store_name, d.division_name
